def p(g):
  h=len(g)
  w=len(g[0])
  o=[[0]*w for _ in range(h)]
  s={}
  for i in range(h):
    for j in range(w):
      v=g[i][j]
      if v:
        if v in s:
          r,c=s.pop(v)
          if i<r:i,r=r,i
          if j<c:j,c=c,j
          for x in range(r,i+1):o[x][c:j+1]=[v]*(j-c+1)
        else:s[v]=(i,j)
  return o

